import { useNavigate } from "react-router-dom";

export default function Login() {
  const navigate = useNavigate();

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-indigo-600 via-purple-600 to-pink-500">

      <div className="bg-white/10 backdrop-blur-xl p-8 rounded-2xl w-full max-w-md border border-white/20">

        <h1 className="text-white text-3xl font-bold text-center">
          Login
        </h1>

        <input className="w-full mt-6 p-3 rounded-lg bg-white/20 text-white placeholder-white outline-none" placeholder="Email" />
        <input className="w-full mt-4 p-3 rounded-lg bg-white/20 text-white placeholder-white outline-none" placeholder="Password" />

        <button
          onClick={() => navigate("/feed")}
          className="w-full mt-6 bg-white text-black py-3 rounded-lg font-semibold hover:bg-gray-200 transition"
        >
          Login
        </button>

      </div>
    </div>
  );
}
